class Solution {
    public char kthCharacter(long k, int[] operations) {
        long length = 1;
        long increment = 0;
        for (int op : operations) {
            if (op == 0) {
                length *= 2;
            } else {
                length *= 2;
                increment++;
            }
        }
        k--;
        long index = k % length;
        long group = k / length;
        char base = 'a';
        return (char) ((base + (increment + index) % 26));
    }
}
